package com.raonmate.backend.notification.api; import com.raonmate.backend.notification.domain.WorkshopNotification; import java.time.Instant; import java.util.UUID; public record NotificationResponse(UUID id,UUID workshopId,String channel,int recipientCount,String message,String status,Instant sentAt){public static NotificationResponse from(WorkshopNotification n){return new NotificationResponse(n.getId(),n.getWorkshop().getId(),n.getChannel(),n.getRecipientCount(),n.getMessage(),n.getStatus(),n.getSentAt());}}
